--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelShop:OnModelInit()
    self:ParseConfig()
    self._conditionChecker=
    {
        [1] = function(para) return gModelPlayer:GetPlayerLv()>=para  end,
        [2] = function(para) return gModelPlayer:GetVipLevel()>=para  end,
        [3] = function(para) return self:CheckServerOpenDay(para) end,
        [4] = function(para) return self:CheckGuildLv(para) end,
        --【G公共支持】删除暗黑战争相关数据
        -- [5] = function(para) return self:CheckDarkWar(para) end,


    }
    self:ModelNetMsgRecv(LProtoIds.ShopListResp,function (...) self:OnShopListResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ShopBuyResp,function (...) self:OnShopBuyResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ShopRefreshResp,function (...) self:OnShopRefreshResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ShopAutoBuySetResp,function (...) self:OnShopAutoBuySetResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ShopAutoBuyResp,function (...) self:OnShopAutoBuyResp(...) end)

    self:ModelEventRecv(EventNames.ON_PLAYER_LEVEL_CHANGE,function (...) self:OnBubbleDataChange() end)
    self:ModelEventRecv(EventNames.PLAYER_VIP_LEVEL_CHANGE,function (...) self:OnBubbleDataChange() end)
    self:ModelEventRecv(EventNames.REFRESH_FUNCTION_STATE,function (...) self:ReqGoodsBubble() end)
    self:ModelEventRecv(EventNames.ON_TIME_ZERO,function ()
        self._isReqed = false
        self:ReqGoodsBubble()
    end)
end

function ModelShop:CheckServerOpenDay(para)
    local dayPast = gLGameLogin:GetServerOpenDay()
    return dayPast>= tonumber(para)
end

function ModelShop:CheckGuildLv(para)
    local haveGuild = gModelGuild:GetBHaveGuild()
    if not haveGuild then
        return false
    end

    local guildLv = gModelGuild:GetGuildLevel()
    return guildLv >= tonumber(para)
end

--在协议数据处理完之后需要调用finish
function ModelShop:OnModelRequest()
    self._shopTable ={}

    if self._shopId then
        self:ShopListReq(self._shopId)
    end

    self:ReqGoodsBubble()

    self:ModelFinish()
end

