function ModelShop:OnShopBuyResp(pb)
    local shopId = pb.shopId
    local goodsId = pb.goodsId
    local num = pb.num

    local goods = self:GetShopItemNetData(shopId,goodsId)
    if not goods then
        return
    end
    goods:AddHasBuyNum(num)

    FireEvent(EventNames.ON_SHOP_BUY_RETURN,pb)

    local checkId = GameTable.StoreConfigRef["commodityId"]
    if goodsId == checkId then
        local show,data = self:CheckShowBubble(shopId)
        FireEvent(EventNames.SHOW_GOODS_BUBBLE,show,data)
    end
end

