function ModelShop:GetShopShow(shopType)
    local curServerId= gModelPlayer:GetServerId()
    local shopId = gModelBackflow:RegressionConfigRefByKey("shopId")
    local t ={}
    for k,v in pairs(GameTable.StoreBasicsDateRef) do
        if shopType == v.shopStoreType and v.type ~= ModelShop.SKIN and v.type ~= ModelShop.FISH then
            --- 皮肤商店移动到时光衣橱那边
            local serverList = self._serverLimitList[v.refId]
            local isSeverAllow = serverList == nil or serverList[curServerId]
            --local isServerLimit = serverList and serverList[curServerId]
            local isShow = gModelFunctionOpen:CheckIsShow(v.functionOpenRefId)
            if isShow then
                if shopId == v.refId then
                    isShow = gModelBackflow:GetBackShopIsOpent(v.refId)

                end
            end
            if isSeverAllow and isShow then
                table.insert(t,v)
            end
        end
    end
    table.sort(t,function (a,b) return a.sequence<b.sequence end)
    return t
end


