function ModelShop:CheckIsUnlockByUnlock(unlock)
    for k,v in ipairs(unlock) do
        local conditionType = v.conditionType
        local conditionPara = v.conditionPara
        local checker = self._conditionChecker[conditionType]
        if checker and not checker(conditionPara) then
            local para = conditionPara
            --【G公共支持】删除暗黑战争相关数据
            -- if conditionType == 5 then
            --     para = conditionPara - gModelDarkWar:GetOpenDay()
            -- end
            --
            local ref =  GameTable.StoreconditionTextRef[conditionType]
            local tip = ref.conditionText
            tip = ccLngText(tip)
            tip = string.replace(tip,tostring(para))
            local msg = ccLngText(ref.conditionTextTip)
            msg = string.replace(msg,tostring(para))
            return false,tip,msg,conditionType
        end
    end
    return true
end
function ModelShop:CheckIsUnlock(unlock,unlockTxt)
    if not string.isempty(unlock) and not string.isempty(unlockTxt)then
        local unlockList = LxDataHelper.ParseItem(unlock) or {}
        for i, v in ipairs(unlockList) do
            local itemNum = gModelItem:GetNumByRefId(v.itemId)
            if itemNum < v.itemNum then
                return false,unlockTxt
            end
        end
    end
    return true
end

