---配置预处理

function ModelShop:ParseConfig()
    self._shopBasicDataT={}

    local serverLimitList = {}

    for k,v in pairs(GameTable.StoreBasicsDateRef) do
        local itemdata = {}
        itemdata.refreshNeed = LxDataHelper.ParseItem(v.refreshNeed)
        itemdata.currency = self:ParseCurrency(v.currency)
        itemdata.screenPage = self:ParseScreenPage(v.screenPage)
        --itemdata.default = v
        self._shopBasicDataT[k]=itemdata

        local str = v.severOpen
        if not string.isempty(str) then
            local idList = LxDataHelper.ParseNumber_Sign(str,';')
            local map = {}
            for k1,v1 in ipairs(idList) do
                 map[v1] = true
            end

            serverLimitList[k] = map
        end


    end

    self._serverLimitList = serverLimitList

    local shopByTypeMap = {}
    local type,price,tprice,rewardList,priceType,unlock,limitCount
    self._shopItemsT ={}
    for k,v in pairs(GameTable.StoreFixedRef) do
        type = v.type
        price = v.price
        rewardList = LxDataHelper.ParseItem_3List(v.reward)
        unlock = self:ParseUnlock(v.unlock)
        limitCount = self:ParseItem_2(v.limitCount)

        tprice = LxDataHelper.ParseItem_3(price)
        if tprice then
            priceType = ModelPopupGift.BUYTYPE_JEWEL
        else
            if string.isempty(price) then
                priceType = ModelPopupGift.BUYTYPE_FREE
                tprice = 0
            else
                priceType = ModelPopupGift.BUYTYPE_MONEY
                tprice = tonumber(price)
            end
        end
        local shopTypeList = shopByTypeMap[type]
        if not shopTypeList then
            shopTypeList = {}
            shopByTypeMap[type] = shopTypeList
        end
        table.insert(shopTypeList,{
            refId = k,
            type = type,
            pageType = v.pageType,
            reward = rewardList,
            buyType = priceType,
            item = tprice,
            sequence = v.sequence,
            itemName = ccLngText(v.itemName),
            unlock = unlock,
            fixDiscount = ccLngText(v.fixDiscount),
            limitCount = limitCount,
            canBuyMore = v.canBuyMore,
            icon = v.icon,
            name = ccLngText(v.name),
            nameBg = v.nameBg,
        })

        local itemdata ={}
        --itemdata.reward = LxDataHelper.ParseItem_3(v.reward)
        itemdata.reward = rewardList[1]
        itemdata.price = LxDataHelper.ParseItem_3(price)
        itemdata.limitCount = limitCount
        --itemdata.limitCount = itemdata.limitCountCfg
        itemdata.unlock = unlock
        itemdata.default = v
        self._shopItemsT[k] = itemdata
    end

    for k,v in pairs(shopByTypeMap) do
        table.sort(v,function(a,b) return a.sequence < b.sequence end)
    end
    self._shopByTypeMap = shopByTypeMap



    local shopItemTypeList = {}
    for k,v in pairs(GameTable.StoreRandomRef) do
        local itemdata ={}
        itemdata.reward = LxDataHelper.ParseItem_3(v.reward)
        itemdata.price = LxDataHelper.ParseItem_3(v.price)
        itemdata.limitCount = self:ParseItem_2(v.limitCount)
        --itemdata.limitCount = itemdata.limitCountCfg
        itemdata.unlock = self:ParseUnlock(v.unlock)
        itemdata.default = v
        self._shopItemsT[k] =itemdata

        local type = v.type
        local shopItemList = shopItemTypeList[type] or {}
        local autoBuy = v.autoBuy or 0
        if autoBuy > 0 then
            table.insert(shopItemList,v)
        end
        shopItemTypeList[type] = shopItemList
    end
    self._shopItemTypeList = shopItemTypeList
end

function ModelShop:GetShopItmeListByType(type)
    local shopItemList = self._shopItemTypeList[type] or {}
    local list = {}
    for i, v in ipairs(shopItemList) do
        local unlock = self:ParseUnlock(v.unlock)
        local unlockB = self:CheckIsUnlockByUnlock(unlock)
        local closeB = false
        if not string.isempty(v.close)then
            local close = self:ParseUnlock(v.close)
            closeB = self:CheckIsUnlockByUnlock(close)
        end
        if unlockB and not closeB then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.autoBuy < b.autoBuy
    end)
    return list
end
