function ModelShop:ParseCurrency(str)
    local strList= string.split(str,'|')
    local itemList = {}
    for k,v in pairs(strList) do
        local currentType = tonumber(v)
        table.insert(itemList,currentType)
    end
    return itemList
end

function ModelShop:ParseScreenPage(str)
    if str=="" then
        return {}
    end
    local strList= string.split(str,',')
    local itemList = {}
    for k,v in pairs(strList) do
        local strs = string.split(v,'=')
        local data=
        {
            filterType = tonumber(strs[1]),
            iconPath = strs[2]
        }
        table.insert(itemList,data)
    end
    return itemList
end


