function ModelShop:ParseItem_2(str)
    local s,e,cap1,cap2 = string.find(str,"(%d+)=([-]*%d+)")
    if not cap1 or not cap2 then
        printInfoN("ModelShop:ParseItem_2, wrong cfg "..str)
    end
    local t = {
        itemId = tonumber(cap1),
        itemNum =tonumber(cap2),
    }

    return t
end


function ModelShop:ParseUnlock(str)
    local strs = string.split(str,',')
    local conditionList = {}
    for k,v in pairs(strs) do
        local s,e,cap1,cap2 = string.find(v,"(%d+)=(%d+)")
        if not cap1 or not cap2 then
            printInfoN("ModelShop:ParseUnlock, wrong cfg "..v)
            break
        end
        local condition =
        {
            conditionType = tonumber(cap1),
            conditionPara = tonumber(cap2)
        }
        table.insert(conditionList,condition)
    end
    return conditionList
end


function ModelShop:GetShopDesc(shopId,curId)
    local shopCfg = self:GetShopRef(shopId)
    local shopDesc = shopCfg.shopDesc
    local idList = LxDataHelper.ParseNumber_Sign(shopDesc,',')
    for k,v in ipairs(idList) do
        if curId == v then
            table.remove(idList,k)
            break
        end
    end

    local cnt = #idList
    local id = nil
    if cnt == 0 then
        id = curId
    else
        local random = math.random(1,cnt)
        id = idList[random]
    end

    local descCfg = GameTable.StoreDescTextRef[id]
    if not descCfg then
        return ""
    end
    local desc = ccLngText(descCfg.text)
    return desc,id
end

function ModelShop:ReqGoodsBubble()

    local funcId = 14400000
    local isOpen = gModelFunctionOpen:CheckIsOpened(funcId)
    if not isOpen then
        return
    end

    if self._isReqed then
        return
    end
    self._isReqed = true
    local jumpShopId = GameTable.StoreConfigRef["jumpShopId"]
    if jumpShopId > 0 then
        self:ShopListReq(jumpShopId)
    end
end

function ModelShop:CheckShowBubble(shopId)

    local goodsId = GameTable.StoreConfigRef["commodityId"]
    local itemdata = self:GetShopItemNetData(shopId,goodsId)
    if not itemdata then
        return
    end

    local goods = self:GetShopItemCfg(goodsId)
    local limitCfg = goods.limitCount
	local priceItem = goods.price
	local goodsRef = goods.default
    local hasBuyNum = itemdata:GetHasBuyNum()
    if limitCfg.itemNum >0 and  hasBuyNum >= limitCfg.itemNum then
        return false
    end

    local isUnlock,tip = self:CheckItemIsUnlock(goodsId)
    local iconList = string.split(GameTable.StoreConfigRef["bubbleIcon"],"|")
    local tagPath
    if isUnlock then
        tagPath = iconList[1]
    else
        tagPath = iconList[2]
        if self._isClickedBubble then
            return false
        end

        local playerLv = gModelPlayer:GetPlayerLv()
        local strs = LxDataHelper.ParseNumber_Sign(GameTable.StoreConfigRef["showLevel"],',')
        local min = tonumber(strs[1])
        local max = tonumber(strs[2])
        if playerLv>max or playerLv< min then
            return false
        end


        local lastTime = tonumber(LPlayerPrefs.goodsBubbleShow) or 0
        local isNewDay = LUtil.IsNewDay(lastTime,GetTimestamp())
        if not isNewDay then
            return false
        end
    end

    local rewardData = goods.reward
    local itemId = rewardData.itemId
    local itemIcon = gModelItem:GetItemImgByRefId(itemId)
	local itemName = gModelItem:GetNameByRefId(itemId)
	local itemColor = gModelItem:GetItemNameColorString(itemId)
	local priceName = gModelItem:GetNameByRefId(priceItem.itemId)
	
    local itemdata =
    {
        bgPath = GameTable.StoreConfigRef["bubbleBg"],
        tagPath = tagPath,
		itemId = itemId,
		itemColor = itemColor,
		itemName = itemName,
		priceNum = priceItem.itemNum,
		priceId = priceItem.itemId,
		priceName = priceName,
		priceDiscount = ccLngText(goodsRef.fixDiscount),
        itemIcon = itemIcon,
        jumpId =  GameTable.StoreConfigRef["jump"],
        goodsId = goodsId
    }

    return true,itemdata
end


function ModelShop:OnBubbleDataChange()
    local jumpShopId = GameTable.StoreConfigRef["jumpShopId"]
    local show,bubbleData = self:CheckShowBubble(jumpShopId)
    FireEvent(EventNames.SHOW_GOODS_BUBBLE,show,bubbleData)
end

function ModelShop:SetGoodsBubbleClicked()
    self._isClickedBubble = true

    self:OnBubbleDataChange()
end

function ModelShop:IsLimitBuy(shopId,goodsId)
    local goods = self:GetShopItemCfg(goodsId)
    if not goods then
        return true
    end
    local limitCfg = goods.limitCount
    if limitCfg.itemNum ==-1 then
        return false
    end
    local itemdata = self:GetShopItemNetData(shopId,goodsId)
    if not itemdata then
        return true
    end
    local hasBuyNum = itemdata:GetHasBuyNum()
    if hasBuyNum>=limitCfg.itemNum then
        return true
    end

    return false

end

function ModelShop:BuyGoods(shopId,goodsId,quick,srcWnd,wnd)
    local isUnlock,tip,msg = self:CheckItemIsUnlock(goodsId)
    if not isUnlock then
        GF.ShowMessage(msg)
        return
    end

    local goods = self:GetShopItemCfg(goodsId)
    local rewardData = goods.reward
    local limitCfg = goods.limitCount

    if limitCfg.itemNum == 1 then
        --local itemId = rewardData.itemId
        local isSkinItem,stateCode,skinRefId = gModelHero:GetSkinStateByItemId(rewardData)
        if isSkinItem then
            if stateCode == 3 or stateCode == 2 then
                gModelHero:ActiveOrWearSkin(skinRefId)
                return
            elseif stateCode == 4 then
                return
            end
        end
    end


    local goodsData = self:GetShopItemNetData(shopId,goodsId)
    if not goodsData then
        return
    end

    local isSoldOut = false
    if limitCfg.itemNum ~=-1 then
        local hasBuyNum = goodsData:GetHasBuyNum()
        if hasBuyNum >= limitCfg.itemNum then
            isSoldOut = true
            GF.ShowMessage(ccClientText(11406))
            return
        end
    end

    local price = goods.price
    local priceItemNum = price.itemNum
    if priceItemNum > 0 then
        local priceItemId  = price.itemId
        local isEnough =  gModelGeneral:CheckItemEnough(priceItemId,priceItemNum,true,srcWnd,wnd)
        if not isEnough then
            return
        end

        local popWndType = goods.default.canBuyMore
        if popWndType ==1 then
            local layer = LGameUI.UI_SORTLAYER_UIUP
            if wnd then
                layer = wnd:GetWndSortLayer()
            end
            gLGameUI:OpenWndWithLayer(layer,"UIDianBuy",{goodsData =goodsData,shopId = shopId,quick =  quick })

            --GF.OpenWndUp("UIDianBuy",{goodsData =goodsData,shopId = shopId,quick =  quick })
        elseif popWndType==2 then

            local priceItemName = gModelItem:GetNameByRefId(priceItemId)
            local numStr = LUtil.NumberCoversion(priceItemNum)
            local cost = numStr..priceItemName


            local buyItemName = gModelGeneral:GetCommonItemName(goods.reward)

            local wndId = 50401
            local func = function()
                self:ShopBuyReq(shopId,goodsId,1,quick)
            end
            gModelGeneral:OpenUIOrdinTips({refId = wndId,func=func,para ={cost,buyItemName},
                                             consume = {priceItemNum,priceItemId}},true)

        elseif popWndType==0 then
            self:ShopBuyReq(shopId,goodsId,1,quick)
        end
    else
        self:ShopBuyReq(shopId,goodsId,1,quick)
    end
end

function ModelShop:GetLimitStr(type)
    local list = self:GetLimitStrList()
    return list[type]
end

function ModelShop:GetLimitStrList()
    if not self._limitTypeText then
        self._limitTypeText ={

            [0] = 11400,
            [1] = 11401,
            [2] = 11403,
            [3] = 11402,
            [4] = 11421
        }
    end
    return self._limitTypeText
end

function ModelShop:GetShopRefByShopType(shopType)
    return self._shopByTypeMap[shopType]
end

function ModelShop:GetShopFixedRefByRefId(RefId)
    local cfg = GameTable.StoreFixedRef
    for i, v in pairs(cfg) do
        if v.refId == RefId then
            return v
        end
    end
    return
end

function ModelShop:GetCanBuyMoreMaxByRefId(RefId)
    local cfg = self:GetShopFixedRefByRefId(RefId)
    if not cfg then
        return
    end
    if cfg.canBuyMore ~= 1 then
        return
    end

    return cfg.canBuyMoreMax

end

function ModelShop:GetShopType6BaseRefId()
    local shopType6List = self._shopType6List
    if not shopType6List then
        shopType6List = {}
        for k,v in pairs(GameTable.StoreBasicsDateRef) do
            if v.type == ModelShop.SKIN then
                table.insert(shopType6List,v.refId)
            end
        end
        table.sort(shopType6List,function(a,b) return a < b end)
        self._shopType6List = shopType6List
    end
    return shopType6List[1]
end

function ModelShop:GetShopTypeRef(refId)
    return GameTable.StoreTypeRef[refId]
end

---@return boolean 是否有手动刷新
function ModelShop:CheckHasRefreshNeed(shopId)
    local cfg = self._shopBasicDataT[shopId].refreshNeed
    if not cfg or #cfg < 1 then return false end
    return true
end

